145	func (b LocalCloneAttemptBackend) Prepare(ctx context.Context, req AttemptBackendPrepareRequest) (*AttemptWorkspace, error) {
146		clonePath := executeBeadClonePath(req.ProjectRoot, req.BeadID, req.AttemptID)
147		if err := os.MkdirAll(filepath.Dir(clonePath), 0o755); err != nil {
148			return nil, fmt.Errorf("creating execute-bead clone parent dir: %w", err)
149		}
150	
151		cloneArgs := localCloneArgs(b.CloneMode, req.ProjectRoot, clonePath)
152		if out, err := internalgit.Command(ctx, req.ProjectRoot, cloneArgs...).CombinedOutput(); err != nil {
153			if shouldRetryCloneWithoutHardlinks(b.CloneMode, out) {
154				_ = os.RemoveAll(clonePath)
155				cloneArgs = localCloneArgs("no-hardlinks", req.ProjectRoot, clonePath)
156				out, err = internalgit.Command(ctx, req.ProjectRoot, cloneArgs...).CombinedOutput()
157			}
158			if err == nil {
159				goto checkout
160			}
161			_ = os.RemoveAll(clonePath)
162			return nil, fmt.Errorf("creating isolated clone: %s: %w", strings.TrimSpace(string(out)), err)
163		}
164	checkout:
165		if out, err := internalgit.Command(ctx, clonePath, "checkout", "--detach", req.BaseRev).CombinedOutput(); err != nil {
166			_ = os.RemoveAll(clonePath)
167			return nil, fmt.Errorf("checking out isolated clone base: %s: %w", strings.TrimSpace(string(out)), err)
168		}
169		seedAttemptCloneUserConfig(ctx, req.ProjectRoot, clonePath)
170		configureAttemptCloneTransientExcludes(clonePath)
171	
172		return &AttemptWorkspace{
173			Backend:     AttemptBackendLocalClone,
174			ProjectRoot: req.ProjectRoot,
175			WorkDir:     clonePath,
176			BeadID:      req.BeadID,
177			AttemptID:   req.AttemptID,
178			BaseRev:     req.BaseRev,
179		}, nil
180	}
