368	func shouldRetryCloneWithoutHardlinks(mode string, out []byte) bool {
369		switch strings.ToLower(strings.TrimSpace(mode)) {
370		case "copy", "no-hardlinks", "no-hardlink":
371			return false
372		}
373		msg := strings.ToLower(string(out))
374		return strings.Contains(msg, "invalid cross-device link") ||
375			strings.Contains(msg, "operation not permitted")
376	}
