395	func configureAttemptCloneTransientExcludes(clonePath string) {
396		out, err := internalgit.Command(context.Background(), clonePath, "rev-parse", "--git-path", "info/exclude").Output()
397		if err != nil {
398			return
399		}
400		excludePath := strings.TrimSpace(string(out))
401		if excludePath == "" {
402			return
403		}
404		if !filepath.IsAbs(excludePath) {
405			excludePath = filepath.Join(clonePath, excludePath)
406		}
407		if err := os.MkdirAll(filepath.Dir(excludePath), 0o755); err != nil {
408			return
409		}
410		raw, _ := os.ReadFile(excludePath)
411		text := string(raw)
412		var additions []string
413		for _, pattern := range []string{"/.gocache/", "/.tmp/"} {
414			if !excludeTextHasPattern(text, pattern) {
415				additions = append(additions, pattern)
416			}
417		}
418		if len(additions) == 0 {
419			return
420		}
421		if len(text) > 0 && !strings.HasSuffix(text, "\n") {
422			text += "\n"
423		}
424		text += strings.Join(additions, "\n") + "\n"
425		_ = os.WriteFile(excludePath, []byte(text), 0o644)
426	}
