848	func sanitizeDockerName(s string) string {
849		var b strings.Builder
850		for _, r := range s {
851			switch {
852			case r >= 'a' && r <= 'z', r >= 'A' && r <= 'Z', r >= '0' && r <= '9', r == '-', r == '_', r == '.':
853				b.WriteRune(r)
854			default:
855				b.WriteByte('-')
856			}
857		}
858		out := strings.Trim(b.String(), "-_.")
859		if out == "" {
860			return "attempt"
861		}
862		if len(out) > 80 {
863			return out[:80]
864		}
865		return out
866	}
